1	// gendoc generates Hugo-compatible markdown documentation for every ddx CLI
2	// command and writes it to website/content/docs/cli/commands/.
3	//
4	// Usage:
5	//
6	//	go run ./tools/gendoc [output-dir]
7	//
8	// If output-dir is omitted it defaults to ../website/content/docs/cli/commands
9	// relative to the cli/ root (i.e. the standard website location).
10	package main
11	
12	import (
13		"fmt"
14		"log"
15		"os"
16		"path/filepath"
17		"strings"
18	
19		"github.com/DocumentDrivenDX/ddx/cmd"
20		"github.com/spf13/cobra"
21		"github.com/spf13/cobra/doc"
22	)
23	
24	func main() {
25		// Determine output directory.
26		outDir := defaultOutDir()
27		if len(os.Args) > 1 {
28			outDir = os.Args[1]
29		}
30	
31		if err := os.MkdirAll(outDir, 0755); err != nil {
32			log.Fatalf("creating output dir %s: %v", outDir, err)
33		}
34	
35		// Build the root command (no working dir needed for doc generation).
36		factory := cmd.NewCommandFactory("/tmp")
37		root := factory.NewRootCommand()
38	
39		// Disable persistent hooks that would try to load config/network during
40		// doc generation — we only need the metadata (Use, Short, Long, Flags).
41		root.PersistentPreRunE = nil
42		root.PersistentPreRun = nil
43		root.PersistentPostRunE = nil
44		root.PersistentPostRun = nil
45	
46		if err := doc.GenMarkdownTreeCustom(root, outDir, frontMatter, linkHandler); err != nil {
47			log.Fatalf("generating docs: %v", err)
48		}
49		if err := injectExamples(outDir, root); err != nil {
50			log.Fatalf("injecting examples: %v", err)
51		}
52	
53		// Write a generated _index.md that lists every top-level command.
54		if err := writeIndex(outDir, root); err != nil {
55			log.Fatalf("writing index: %v", err)
56		}
57	
58		fmt.Printf("docs written to %s\n", outDir)
59	}
60	
61	// frontMatter returns Hugo front matter for the given filename.
62	// cobra/doc passes the full path; we derive the title from the basename.
63	func frontMatter(filename string) string {
64		base := filepath.Base(filename)
65		name := strings.TrimSuffix(base, ".md")
66	
67		// Convert "ddx_bead_create" → "bead create"
68		title := strings.TrimPrefix(name, "ddx")
69		title = strings.TrimPrefix(title, "_")
70		title = strings.ReplaceAll(title, "_", " ")
71		if title == "" {
72			title = "ddx"
73		}
74	
75		// Weight: root gets 1; subcommands sorted alphabetically get higher weights.
76		// We use a simple fixed value — Hugo sorts within the section alphabetically.
77		return fmt.Sprintf("---\ntitle: %q\ngenerated: true\n---\n\n", title)
78	}
79	
80	// linkHandler rewrites cobra/doc cross-links so they point to the correct
81	// Hugo page path instead of neighbouring .md files.
82	func linkHandler(filename string) string {
83		base := filepath.Base(filename)
84		name := strings.TrimSuffix(base, ".md")
85		return "/docs/cli/commands/" + name + "/"
86	}
87	
88	// writeIndex writes an _index.md that lists each top-level command with its
89	// short description, linking to the generated command page.
90	func writeIndex(outDir string, root *cobra.Command) error {
91		var sb strings.Builder
92		sb.WriteString("---\ntitle: \"Command Reference\"\nweight: 10\n---\n\n")
93		sb.WriteString("Auto-generated reference for every `ddx` command.\n\n")
94		sb.WriteString("| Command | Description |\n")
95		sb.WriteString("|---------|-------------|\n")
96	
97		for _, sub := range root.Commands() {
98			if sub.Hidden {
99				continue
100			}
101			name := sub.Name()
102			short := sub.Short
103			link := linkHandler("ddx_" + name + ".md")
104			sb.WriteString(fmt.Sprintf("| [`ddx %s`](%s) | %s |\n", name, link, short))
105		}
106	
107		return os.WriteFile(filepath.Join(outDir, "_index.md"), []byte(sb.String()), 0644)
108	}
109	
110	func injectExamples(outDir string, root *cobra.Command) error {
111		for _, cmd := range visibleCommands(root) {
112			example := strings.TrimSpace(cmd.Example)
113			if example == "" {
114				continue
115			}
116			filename := filepath.Join(outDir, commandDocName(cmd)+".md")
117			raw, err := os.ReadFile(filename)
118			if err != nil {
119				return err
120			}
121			content := string(raw)
122			if strings.Contains(content, "\n### Examples\n") {
123				continue
124			}
125			section := "\n### Examples\n\n```\n" + example + "\n```\n"
126			switch {
127			case strings.Contains(content, "\n### Options\n"):
128				content = strings.Replace(content, "\n### Options\n", section+"\n### Options\n", 1)
129			case strings.Contains(content, "\n### SEE ALSO\n"):
130				content = strings.Replace(content, "\n### SEE ALSO\n", section+"\n### SEE ALSO\n", 1)
131			default:
132				content += section
133			}
134			if err := os.WriteFile(filename, []byte(content), 0o644); err != nil {
135				return err
136			}
137		}
138		return nil
139	}
140	
141	func visibleCommands(root *cobra.Command) []*cobra.Command {
142		var out []*cobra.Command
143		var walk func(*cobra.Command)
144		walk = func(c *cobra.Command) {
145			if c == nil {
146				return
147			}
148			for _, sub := range c.Commands() {
149				if sub.Hidden {
150					continue
151				}
152				out = append(out, sub)
153				walk(sub)
154			}
155		}
156		walk(root)
157		return out
158	}
159	
160	func commandDocName(c *cobra.Command) string {
161		parts := strings.Fields(c.CommandPath())
162		return strings.Join(parts, "_")
163	}
164	
165	// defaultOutDir returns the default output directory relative to the location
166	// of this source file (which lives at cli/tools/gendoc/).
167	func defaultOutDir() string {
168		// When run as "go run ./tools/gendoc" from cli/, the working directory is cli/.
169		// Walk up until we find the website/ sibling directory.
170		cwd, err := os.Getwd()
171		if err != nil {
172			return "website/content/docs/cli/commands"
173		}
174	
175		// If running from cli/ directory (normal case):
176		candidate := filepath.Join(cwd, "..", "website", "content", "docs", "cli", "commands")
177		if _, err := os.Stat(filepath.Join(cwd, "..", "website")); err == nil {
178			return candidate
179		}
180	
181		// Fallback: relative to cwd
182		return filepath.Join(cwd, "website", "content", "docs", "cli", "commands")
183	}
