// test-timing reads go test -json output and emits a Markdown table of the
// top N slowest individual tests, sorted by elapsed time descending.
//
// Usage:
//
//	go run ./tools/test-timing [N] [file]
//
// N defaults to 20. If file is omitted, reads from stdin.
package main

import (
	"bufio"
	"encoding/json"
	"fmt"
	"io"
	"os"
	"sort"
	"strconv"
	"strings"
)

type testEvent struct {
	Action  string  `json:"Action"`
	Package string  `json:"Package"`
	Test    string  `json:"Test"`
	Elapsed float64 `json:"Elapsed"`
}

type testResult struct {
	Package string
	Test    string
	Elapsed float64
	Action  string
}

func main() {
	n := 20
	var r io.Reader = os.Stdin

	args := os.Args[1:]
	for _, arg := range args {
		if v, err := strconv.Atoi(arg); err == nil && v > 0 {
			n = v
			continue
		}
		f, err := os.Open(arg)
		if err != nil {
			fmt.Fprintf(os.Stderr, "error opening %s: %v\n", arg, err)
			os.Exit(1)
		}
		defer f.Close() //nolint:gocritic
		r = f
	}

	var results []testResult
	scanner := bufio.NewScanner(r)
	scanner.Buffer(make([]byte, 1024*1024), 1024*1024)
	for scanner.Scan() {
		line := scanner.Text()
		if !strings.HasPrefix(line, "{") {
			continue
		}
		var ev testEvent
		if err := json.Unmarshal([]byte(line), &ev); err != nil {
			continue
		}
		if ev.Test == "" {
			continue
		}
		if ev.Action != "pass" && ev.Action != "fail" && ev.Action != "skip" {
			continue
		}
		results = append(results, testResult{
			Package: ev.Package,
			Test:    ev.Test,
			Elapsed: ev.Elapsed,
			Action:  ev.Action,
		})
	}
	if err := scanner.Err(); err != nil {
		fmt.Fprintf(os.Stderr, "read error: %v\n", err)
		os.Exit(1)
	}

	sort.Slice(results, func(i, j int) bool {
		return results[i].Elapsed > results[j].Elapsed
	})
	if len(results) > n {
		results = results[:n]
	}

	fmt.Printf("# Test Timing Summary — Top %d Slowest Tests\n\n", n)
	if len(results) == 0 {
		fmt.Println("No test timing data found.")
		return
	}
	fmt.Printf("| Rank | Test | Package | Elapsed (s) | Result |\n")
	fmt.Printf("|------|------|---------|-------------|--------|\n")
	for i, res := range results {
		fmt.Printf("| %d | `%s` | `%s` | %.3f | %s |\n",
			i+1, res.Test, res.Package, res.Elapsed, res.Action)
	}
}
